Vtiger_Detail_Js("Calendar_Detail_Js",{deleteRecord:function(e){var t=app.vtranslate("LBL_DELETE_CONFIRMATION");Vtiger_Helper_Js.showConfirmationBox({message:t}).then(function(t){app.showModalWindow($(".typeRemoveModal").clone(),function(t){t.find(".typeSavingBtn").click(function(t){var n=$(t.currentTarget);app.hideModalWindow(),AppConnector.request(e+"&ajaxDelete=true&typeRemove="+n.data("value")).then(function(e){1==e.success?window.location.href=e.result:Vtiger_Helper_Js.showPnotify(e.error.message)})})})})}},{});